use clap::{CommandFactory, Parser, Subcommand, ValueEnum};
use clap_complete::{generate, Shell};
use std::fs::File;
use std::io::{self, Read, Write};
use std::process::ExitCode;

#[derive(Parser)]
#[command(
    name = "code-minimap",
    version,
    about = "A high performance code minimap generator",
    long_about = None,
    arg_required_else_help = false,
)]
struct Cli {
    /// Specify horizontal scale factor
    #[arg(short = 'H', long = "horizontal-scale", value_name = "HSCALE", default_value = "1.0")]
    hscale: f64,

    /// Specify vertical scale factor
    #[arg(short = 'V', long = "vertical-scale", value_name = "VSCALE", default_value = "1.0")]
    vscale: f64,

    /// Specify padding width
    #[arg(long = "padding", value_name = "PADDING")]
    padding: Option<usize>,

    /// Specify input encoding
    #[arg(long = "encoding", value_name = "ENCODING", default_value = "utf8-lossy", value_enum)]
    encoding: Encoding,

    /// File to read
    file: Option<String>,

    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Subcommand)]
enum Commands {
    /// Generate shell completion file
    Completion {
        /// Target shell name
        shell: Shell,
    },
}

#[derive(Clone, Copy, ValueEnum, PartialEq)]
enum Encoding {
    #[value(name = "utf8-lossy")]
    Utf8Lossy,
    #[value(name = "utf8")]
    Utf8,
}

fn main() -> ExitCode {
    let cli = Cli::parse();

    if let Some(Commands::Completion { shell }) = cli.command {
        let mut cmd = Cli::command();
        generate(shell, &mut cmd, "code-minimap", &mut io::stdout());
        return ExitCode::SUCCESS;
    }

    // Read input
    let raw: Vec<u8> = if let Some(path) = &cli.file {
        match File::open(path) {
            Ok(mut f) => {
                let mut v = Vec::new();
                if let Err(e) = f.read_to_end(&mut v) {
                    eprintln!("code-minimap: {}", e);
                    return ExitCode::from(1);
                }
                v
            }
            Err(e) => {
                eprintln!("code-minimap: {}", e);
                return ExitCode::from(1);
            }
        }
    } else {
        let mut v = Vec::new();
        if let Err(e) = io::stdin().read_to_end(&mut v) {
            eprintln!("code-minimap: {}", e);
            return ExitCode::from(1);
        }
        v
    };

    let text: String = match cli.encoding {
        Encoding::Utf8 => match std::str::from_utf8(&raw) {
            Ok(s) => s.to_owned(),
            Err(_) => {
                eprintln!("code-minimap: stream did not contain valid UTF-8");
                return ExitCode::from(1);
            }
        },
        Encoding::Utf8Lossy => String::from_utf8_lossy(&raw).into_owned(),
    };

    render(&text, cli.hscale, cli.vscale, cli.padding);
    ExitCode::SUCCESS
}

fn render(text: &str, hscale: f64, vscale: f64, padding: Option<usize>) {
    let lines: Vec<&str> = text.lines().collect();
    if lines.is_empty() {
        return;
    }

    let vscale = vscale.min(1.0);

    // Compute per-line widths and masks
    let n_lines = lines.len();
    let mut line_widths: Vec<usize> = Vec::with_capacity(n_lines);
    let mut line_masks: Vec<Vec<bool>> = Vec::with_capacity(n_lines);

    for line in &lines {
        let trimmed = line.trim_end();
        let width = trimmed
            .char_indices()
            .last()
            .map(|(i, _)| i + 1)
            .unwrap_or(0);
        let first_non_ws = trimmed
            .char_indices()
            .find(|(_, c)| !c.is_whitespace())
            .map(|(i, _)| i)
            .unwrap_or(width);

        let mut mask = vec![false; width];
        for i in first_non_ws..width {
            mask[i] = true;
        }
        line_widths.push(width);
        line_masks.push(mask);
    }

    // Forward V mapping: line idx -> dot row
    let line_dot_rows: Vec<usize> = (0..n_lines)
        .map(|i| ((i as f64) * vscale).floor() as usize)
        .collect();

    let dot_height = line_dot_rows.iter().max().copied().unwrap_or(0) + 1;
    let braille_rows = (dot_height + 3) / 4;

    let stdout = io::stdout();
    let mut out = stdout.lock();

    // Pre-bucket lines by dot row
    let mut lines_in_dot_row: Vec<Vec<usize>> = vec![Vec::new(); dot_height];
    for (i, &dr) in line_dot_rows.iter().enumerate() {
        lines_in_dot_row[dr].push(i);
    }

    let mut buf = Vec::with_capacity(8192);

    for brow in 0..braille_rows {
        let dot_start = brow * 4;
        let dot_end = ((brow + 1) * 4).min(dot_height);

        // Determine max line width among lines in this braille row
        let mut max_w: usize = 0;
        for dr in dot_start..dot_end {
            for &li in &lines_in_dot_row[dr] {
                if line_widths[li] > max_w {
                    max_w = line_widths[li];
                }
            }
        }
        let effective_w = max_w.max(1);
        let dot_width = ((effective_w as f64) * hscale).floor() as usize;
        let braille_cols = (dot_width + 1) / 2;

        buf.clear();

        for bcol in 0..braille_cols {
            let mut bits: u8 = 0;
            for dy in 0..4 {
                let dot_row = brow * 4 + dy;
                if dot_row >= dot_height {
                    continue;
                }
                for dx in 0..2 {
                    let dot_col = bcol * 2 + dx;
                    if dot_col >= dot_width {
                        continue;
                    }
                    // Inverse mapping for H
                    let src_col = ((dot_col as f64) / hscale).floor() as usize;
                    let on = lines_in_dot_row[dot_row].iter().any(|&li| {
                        src_col < line_masks[li].len() && line_masks[li][src_col]
                    });
                    if on {
                        let bit = match (dx, dy) {
                            (0, 0) => 0,
                            (0, 1) => 1,
                            (0, 2) => 2,
                            (1, 0) => 3,
                            (1, 1) => 4,
                            (1, 2) => 5,
                            (0, 3) => 6,
                            (1, 3) => 7,
                            _ => unreachable!(),
                        };
                        bits |= 1 << bit;
                    }
                }
            }
            let cp = 0x2800u32 + bits as u32;
            let ch = char::from_u32(cp).unwrap();
            let mut tmp = [0u8; 4];
            buf.extend_from_slice(ch.encode_utf8(&mut tmp).as_bytes());
        }
        if let Some(p) = padding {
            if p > braille_cols {
                for _ in 0..(p - braille_cols) {
                    buf.push(b' ');
                }
            }
        }
        buf.push(b'\n');
        out.write_all(&buf).unwrap();
    }
}

