            .map(|(i, _)| i + 1)
            .unwrap_or(0);
        let first_non_ws = trimmed
            .char_indices()
            .find(|(_, c)| !c.is_whitespace())
            .map(|(i, _)| i)
            .unwrap_or(width);

        let mut mask = vec![false; width];
        for i in first_non_ws..width {
            mask[i] = true;
        }
        line_widths.push(width);
        line_masks.push(mask);
    }

    // Forward V mapping: line idx -> dot row
    let line_dot_rows: Vec<usize> = (0..n_lines)
        .map(|i| ((i as f64) * vscale).floor() as usize)
        .collect();

    let dot_height = line_dot_rows.iter().max().copied().unwrap_or(0) + 1;
    let braille_rows = (dot_height + 3) / 4;

    let stdout = io::stdout();
    let mut out = stdout.lock();

    // Pre-bucket lines by dot row
    let mut lines_in_dot_row: Vec<Vec<usize>> = vec![Vec::new(); dot_height];
    for (i, &dr) in line_dot_rows.iter().enumerate() {
        lines_in_dot_row[dr].push(i);
    }

    let mut buf = Vec::with_capacity(8192);

    for brow in 0..braille_rows {
        let dot_start = brow * 4;
        let dot_end = ((brow + 1) * 4).min(dot_height);

        // Determine max line width among lines in this braille row
        let mut max_w: usize = 0;
        for dr in dot_start..dot_end {
            for &li in &lines_in_dot_row[dr] {
                if line_widths[li] > max_w {
                    max_w = line_widths[li];
                }
            }
        }
        let effective_w = max_w.max(1);
        let dot_width = ((effective_w as f64) * hscale).floor() as usize;
        let braille_cols = (dot_width + 1) / 2;

