            .char_indices()
            .find(|(_, c)| !c.is_whitespace())
            .map(|(i, _)| i)
            .unwrap_or(width);

        let dot_width = ((width as f64) * hscale).floor() as usize;
        let mut dot_mask = vec![false; dot_width];

        // For each source column from first_non_ws to width-1, mark dot range
        for i in first_non_ws..width {
            let ds = ((i as f64) * hscale).floor() as usize;
            let de = (((i + 1) as f64) * hscale).floor() as usize;
            for d in ds..de.min(dot_width) {
                dot_mask[d] = true;
            }
        }

        line_dot_widths.push(dot_width);
        line_dot_masks.push(dot_mask);
    }

