        let dot_row_start = brow * 4;
        let dot_row_end = ((brow + 1) * 4).min(dot_height);

        // Determine max dot width among lines in this braille row, with min 1
        let mut row_dot_width: usize = 0;
        for dr in dot_row_start..dot_row_end {
            for &li in &lines_in_dot_row[dr] {
                if line_dot_widths[li] > row_dot_width {
                    row_dot_width = line_dot_widths[li];
                }
            }
        }
        // If no lines or all are empty, ensure min braille char of 1 if any line maps here
        if row_dot_width == 0 {
            // Effectively "empty line" -> use width 1 (just one empty braille char column)
            let any_line_here = (dot_row_start..dot_row_end).any(|dr| !lines_in_dot_row[dr].is_empty());
            if any_line_here {
                // Compute effective dot width as floor(1 * hscale)
                row_dot_width = (hscale).floor() as usize;
            }
