                        bits |= 1 << bit;
                    }
                }
            }
            let cp = 0x2800u32 + bits as u32;
            let ch = char::from_u32(cp).unwrap();
            let mut tmp = [0u8; 4];
            buf.extend_from_slice(ch.encode_utf8(&mut tmp).as_bytes());
        }
        if let Some(p) = padding {
            if p > braille_cols {
                for _ in 0..(p - braille_cols) {
                    buf.push(b' ');
                }
            }
        }
        buf.push(b'\n');
        out.write_all(&buf).unwrap();
    }
}

