                    let dot_col = bcol * 2 + dx;
                    if dot_col >= row_dot_width {
                        continue;
                    }
                    let on = lines_in_dot_row[dot_row].iter().any(|&li| {
                        dot_col < line_dot_masks[li].len() && line_dot_masks[li][dot_col]
                    });
                    if on {
