        args.extend(["-V", str(random.choice([0.0, 0.1, 0.25, 0.5, 0.75, 1.0]))])
    if random.random() < 0.4:
        args.extend(["--padding", str(random.choice([0, 1, 5, 10, 30]))])
    if random.random() < 0.2:
        args.extend(["--encoding", random.choice(["utf8", "utf8-lossy"])])
    return args

